mapper.select:
select nc.id, nc.name as ncName, nc.title, nc.band_number as bandNumber, nc.nc_path as ncPath, nc.img_path as imgPath,
nc.satellite_type as satelliteType, nc.resolution, nc.img_type as imgType, nc.process_type as processType,
nc.start_time as startTime, nc.end_time as endTime, ST_ASGeoJSON(nc.geometry) as ncGeometry, china.name, china.gb,
ST_AsGeoJSON(china.geometry) as geometry
from nc
join china ON ST_Contains(nc.geometry, china.geometry)
 1=1
    and nc_name like '%' || #{name} || '%'
    and nc.title like '%' || #{title} || '%'
    and nc.band_number = #{band_number}
    and china.name like '%' || #{region_name} || '%'
    and nc.satellite_type = #{satellite_type}
    and nc.resolution = #{resolution}
    and nc.img_type = #{img_type}
    and nc.process_type = #{process_type}
    and nc.start_time >= #{begin_date}
    and nc.end_time <= #{end_date}

order by nc.id
limit #{page_size} offset #{offset}

select count(*)
from nc
join china ON ST_Contains(nc.geometry, china.geometry)
 1=1
    and nc_name like '%' || #{name} || '%'
    and nc.title like '%' || #{title} || '%'
    and nc.band_number = #{band_number}
    and china.name like '%' || #{region_name} || '%'
    and nc.satellite_type = #{satellite_type}
    and nc.resolution = #{resolution}
    and nc.img_type = #{img_type}
    and nc.process_type = #{process_type}
    and nc.start_time > #{begin_date}
    and nc.end_time < #{end_date}
